query:
SELECT COUNT(*) as puzzles_last_24h, COUNT(DISTINCT deviceId) as unique_players_24h
FROM puzzle_attempts
WHERE completedAt > DATE_SUB(NOW(), INTERVAL 24 HOUR);

SELECT COUNT(*) as puzzles_last_1h, COUNT(DISTINCT deviceId) as unique_players_1h
FROM puzzle_attempts
WHERE completedAt > DATE_SUB(NOW(), INTERVAL 1 HOUR);

SELECT name, lastActive FROM active_sessions ORDER BY lastActive DESC LIMIT 10;

